import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface DailyStats {
  steps: number;
  calories: number;
}

interface WeeklyActivity {
  day: string;
  steps: number;
}

interface FitnessTrackerData {
  dailyStats: DailyStats;
  weeklyActivity: WeeklyActivity[];
}

export default function Widget() {
  const { dailyStats, weeklyActivity } = response.data as FitnessTrackerData;
  const { theme, primaryColor, accentColor } = response.meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: theme === 'dark' ? '#1E1E1E' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
              Daily Stats
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Steps: {dailyStats.steps.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Calories: {dailyStats.calories.toLocaleString()}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: weeklyActivity.map(activity => activity.steps),
                  color: accentColor,
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyActivity.map(activity => activity.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'steps' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: theme === 'dark' ? '#B0B0B0' : '#6B7280' }}
              />
              <ChartsYAxis
                axisId="steps"
                tickLabelStyle={{ fontSize: 10, fill: theme === 'dark' ? '#B0B0B0' : '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
